         return NV;
-
+  // Fold nested select where condition is (C1 && C2) and false value is select(C1, A, B).
+  // select (select C1, C2, false), C, select(C1, A, B)
+  // -> select C1, select(C2, C, A), B
+  // This transforms: if (C1 && C2) then C else (C1 ? A : B)
+  // into: if C1 then (if C2 then C else A) else B
+  if (auto *CondSI = dyn_cast<SelectInst>(CondVal)) {
+    if (auto *FalseSI = dyn_cast<SelectInst>(FalseVal)) {
+      if (CondSI->getFalseValue() == ConstantInt::getFalse(CondVal->getType())) {
+        Value *C1 = CondSI->getCondition();
+        Value *C2 = CondSI->getTrueValue();
+        if (FalseSI->getCondition() == C1 && CondSI->hasOneUse() &&
+            FalseSI->user_back() == &SI) {
+          Value *A = FalseSI->getTrueValue();
+          Value *B = FalseSI->getFalseValue();
+          Value *InnerSel = Builder.CreateSelect(C2, TrueVal, A, SI.getName() + ".inner");
+          return SelectInst::Create(C1, InnerSel, B, SI.getName());
+        }
+      }
+    }
+  }
+  // Fold nested select where condition is (C1 || C2) and true value is select(C1, A, B).
+  // select (select C1, true, C2), select(C1, A, B), D
+  // -> select C1, A, select(C2, B, D)
+  // This transforms: if (C1 || C2) then (C1 ? A : B) else D
+  // into: if C1 then A else (if C2 then B else D)
+  if (auto *CondSI = dyn_cast<SelectInst>(CondVal)) {
+    if (auto *TrueSI = dyn_cast<SelectInst>(TrueVal)) {
+      if (CondSI->getTrueValue() == ConstantInt::getTrue(CondVal->getType())) {
+        Value *C1 = CondSI->getCondition();
+        Value *C2 = CondSI->getFalseValue();
+        if (TrueSI->getCondition() == C1 && CondSI->hasOneUse() &&
+            TrueSI->user_back() == &SI) {
+          Value *A = TrueSI->getTrueValue();
+          Value *B = TrueSI->getFalseValue();
+          Value *InnerSel = Builder.CreateSelect(C2, B, FalseVal, SI.getName() + ".inner");
+          return SelectInst::Create(C1, A, InnerSel, SI.getName());
+        }
+      }
+    }
+  }
+  }
